#!/usr/bin/env python3
from flask import Flask, request, jsonify, abort

app = Flask(__name__)

# In-memory storage
notes = {}
next_id = 1


def get_next_id():
    global next_id
    _id = next_id
    next_id += 1
    return _id


@app.route("/notes", methods=["GET"])
def list_notes():
    # Optional simple search: ?q=...
    q = request.args.get("q")
    result = list(notes.values())
    if q:
        q_lower = q.lower()
        result = [n for n in result if q_lower in n["title"].lower()
                  or q_lower in n["content"].lower()]
    return jsonify(result), 200


@app.route("/notes/<int:note_id>", methods=["GET"])
def get_note(note_id):
    note = notes.get(note_id)
    if not note:
        abort(404)
    return jsonify(note), 200


@app.route("/notes", methods=["POST"])
def create_note():
    if not request.is_json:
        abort(400)
    data = request.get_json()
    title = data.get("title")
    content = data.get("content", "")
    if not isinstance(title, str) or title.strip() == "":
        abort(400)
    note_id = get_next_id()
    note = {"id": note_id, "title": title, "content": content}
    notes[note_id] = note
    return jsonify(note), 201


@app.route("/notes/<int:note_id>", methods=["PUT", "PATCH"])
def update_note(note_id):
    note = notes.get(note_id)
    if not note:
        abort(404)
    if not request.is_json:
        abort(400)
    data = request.get_json()
    # For PUT/PATCH, both fields are optional but must be valid if present.
    if "title" in data:
        title = data["title"]
        if not isinstance(title, str) or title.strip() == "":
            abort(400)
        note["title"] = title
    if "content" in data:
        content = data["content"]
        if not isinstance(content, str):
            abort(400)
        note["content"] = content
    return jsonify(note), 200


@app.route("/notes/<int:note_id>", methods=["DELETE"])
def delete_note(note_id):
    if note_id not in notes:
        abort(404)
    del notes[note_id]
    return "", 204


# Simple JSON error responses
@app.errorhandler(400)
def bad_request(e):
    return jsonify(error="bad_request"), 400


@app.errorhandler(404)
def not_found(e):
    return jsonify(error="not_found"), 404


if __name__ == "__main__":
    app.run(debug=True)
